import {
  ApplicationConfig,
  importProvidersFrom,
  inject,
  provideAppInitializer,
  provideExperimentalZonelessChangeDetection,
} from '@angular/core';
import { LocationStrategy, HashLocationStrategy } from '@angular/common';
import { provideRouter } from '@angular/router';
import { provideAnimationsAsync } from '@angular/platform-browser/animations/async';
import { providePrimeNG } from 'primeng/config';
import Aura from '@primeng/themes/aura';

import { routes } from './app.routes';
import {
  provideHttpClient,
  withInterceptorsFromDi,
  withInterceptors,
  HttpHeaders,
} from '@angular/common/http';
import { CoreModule } from './core/core.module';
import { ApiModule, Configuration, ConfigurationParameters } from './api';
import { environment } from '../environments/environment';
import { ConfirmationService, MessageService } from 'primeng/api';
import { ToastModule } from 'primeng/toast';
import { ApiUrlInterceptor } from './core/interceptors/api-url.interceptor';
import { BroadcastMessageService } from './core/services/message.service';
import { DialogService } from 'primeng/dynamicdialog';
import { provideApollo } from 'apollo-angular';
import { HttpLink } from 'apollo-angular/http';
import { InMemoryCache, split } from '@apollo/client/core';
import { WebSocketLink } from '@apollo/client/link/ws';
import { ApiUrlService } from './core/services/api-url.service';
import { isDefined } from './shared/utils';
import { getMainDefinition } from '@apollo/client/utilities';
import { initializeFeatureDefaults } from './core/models';
import { of } from 'rxjs';

export function apiConfigFactory(): Configuration {
  const params: ConfigurationParameters = { basePath: environment.apiUrls[0] };
  return new Configuration(params);
}

export const appConfig: ApplicationConfig = {
  providers: [
    provideExperimentalZonelessChangeDetection(),
    provideRouter(routes),
    provideAnimationsAsync(),
    providePrimeNG({
      theme: {
        preset: Aura,
        options: { prefix: 'p', darkModeSelector: 'p-dark' },
      },
    }),
    provideHttpClient(
      withInterceptorsFromDi(),
      withInterceptors([ApiUrlInterceptor]),
    ),
    provideApollo(() => {
      const apiUrlService = inject(ApiUrlService);
      const httpLink = inject(HttpLink);

      // Get base URL from ApiUrlService
      const baseUrl = apiUrlService.getCurrentApiUrl();

      // Create HTTP link for queries and mutations
      const http = httpLink.create({
        uri: `${baseUrl}/gql`,
        // Add auth headers if needed
        headers: new HttpHeaders(
          isDefined(localStorage.getItem('accessToken'))
            ? { 'x-access-token': `${localStorage.getItem('accessToken')}` }
            : {},
        ),
      });

      // For WebSocket, use wss for HTTPS, ws for HTTP
      const wsUrl =
        baseUrl
          .replace(/^http:\/\//, 'ws://')
          .replace(/^https:\/\//, 'wss://') + '/gql';

      // CHANGE: Use old WebSocketLink implementation
      const wsLink = new WebSocketLink({
        uri: wsUrl,
        options: {
          reconnect: true,
          timeout: 30000,
          lazy: true,
          // Authentication
          connectionParams: {
            'x-access-token': localStorage.getItem('accessToken') ?? '',
          },
          inactivityTimeout: 60000, // 1 minute
        },
      });

      // Split links based on operation type
      const splitLink = split(
        // Split based on operation type
        ({ query }) => {
          const definition = getMainDefinition(query);
          return (
            definition.kind === 'OperationDefinition' &&
            definition.operation === 'subscription'
          );
        },
        wsLink, // Use WebSocket for subscriptions
        http, // Use HTTP for queries and mutations
      );

      return {
        link: splitLink,
        cache: new InMemoryCache(),
        defaultOptions: {
          watchQuery: { fetchPolicy: 'network-only', errorPolicy: 'all' },
          query: { fetchPolicy: 'network-only', errorPolicy: 'all' },
          mutation: { fetchPolicy: 'network-only', errorPolicy: 'all' },
        },
      };
    }),
    provideAppInitializer(() => of(initializeFeatureDefaults())),
    importProvidersFrom([
      CoreModule,
      ApiModule.forRoot(apiConfigFactory),
      ToastModule,
    ]),
    { provide: LocationStrategy, useClass: HashLocationStrategy },
    MessageService,
    BroadcastMessageService,
    DialogService,
    ConfirmationService,
  ],
};
