import {
  HttpInterceptor,
  HttpRequest,
  HttpHandler,
  HttpEvent,
  HttpErrorResponse,
} from '@angular/common/http';
import { inject, Injectable } from '@angular/core';
import {
  Observable,
  catchError,
  throwError,
  switchMap,
  BehaviorSubject,
  filter,
  take,
  retry,
  timer,
} from 'rxjs';
import { AuthService } from '../services/auth.service';
import { AuthTokenManagerService } from '../services/auth-token-manager.service';
import {
  ApiErrorResponse,
  ApiRequest,
  ApiResponse,
  AuthResponse,
} from '../models/auth.model';
import { ErrorReasons } from '../models/error-reasons.enum';
import { ToastService } from '../services/toast.service';
import { AuthDataService } from '../services/auth-data.service';
import { isDefined } from '../../shared/utils';

@Injectable({
  providedIn: 'root',
})
export class AuthInterceptorService implements HttpInterceptor {
  private refreshTokenInProgress = false;
  private readonly refreshTokenSubject: BehaviorSubject<string | null> =
    new BehaviorSubject<string | null>(null);
  private readonly toastService = inject(ToastService);
  private readonly authService = inject(AuthService);
  private readonly authTokenManagerService = inject(AuthTokenManagerService);
  private readonly authDataService = inject(AuthDataService);

  intercept(
    req: HttpRequest<ApiRequest>,
    next: HttpHandler,
  ): Observable<HttpEvent<ApiResponse>> {
    const accessToken = this.authTokenManagerService.getAccessToken();
    if (isDefined(accessToken)) {
      req = this.addToken(req, accessToken);
    }

    return next.handle(req).pipe(
      retry({
        count: 2,
        delay: (error: HttpErrorResponse, retryCount: number) => {
          // Only retry for specific error types that make sense to retry
          if (this.shouldRetryError(error)) {
            // Exponential backoff: 1s, 2s
            return timer(1000 * Math.pow(2, retryCount - 1));
          }
          // Don't retry for other errors, throw immediately
          throw error;
        },
      }),
      catchError((error) => this.handleError(req, next, error)),
    );
  }

  private addToken(
    req: HttpRequest<ApiRequest>,
    token: string,
  ): HttpRequest<ApiRequest> {
    return req.clone({
      setHeaders: {
        'x-access-token': `${token}`,
      },
    });
  }

  private handle401Error(
    req: HttpRequest<ApiRequest>,
    next: HttpHandler,
    refreshToken: string,
  ): Observable<HttpEvent<ApiResponse>> {
    if (!this.refreshTokenInProgress) {
      this.refreshTokenInProgress = true;
      this.refreshTokenSubject.next(null);

      return this.authService.refreshToken(refreshToken).pipe(
        switchMap((authResponse: AuthResponse) => {
          this.refreshTokenInProgress = false;
          this.refreshTokenSubject.next(authResponse.accessToken);
          this.authTokenManagerService.storeTokens(authResponse);
          return next.handle(this.addToken(req, authResponse.accessToken));
        }),
        catchError((error) => {
          this.refreshTokenInProgress = false;
          this.authDataService.forceLogout();
          return throwError(
            () => new Error(`Token refresh error: ${error.message}`),
          );
        }),
      );
    } else {
      return this.refreshTokenSubject.pipe(
        filter((token) => token != null),
        take(1),
        switchMap((token) => next.handle(this.addToken(req, token))),
      );
    }
  }

  private handleError(
    req: HttpRequest<ApiRequest>,
    next: HttpHandler,
    error: HttpErrorResponse,
  ): Observable<HttpEvent<ApiResponse>> {
    const errorObject = this.createErrorObject(error);

    if (error.status === 401) {
      if (req.url.includes('/auth/signin')) {
        this.showToastForError(errorObject);
        return throwError(() => errorObject);
      }

      const refreshToken = this.authTokenManagerService.getRefreshToken();
      return isDefined(refreshToken)
        ? this.handle401Error(req, next, refreshToken).pipe(
            catchError((refreshError) => {
              this.authDataService.forceLogout();
              this.showToastForError(errorObject);
              return throwError(() => refreshError);
            }),
          )
        : throwError(() => errorObject);
    }

    this.showToastForError(errorObject);
    return throwError(() => new Error(errorObject.errorMessage));
  }

  private createErrorObject(error: HttpErrorResponse): ApiErrorResponse {
    if (!navigator.onLine) {
      return {
        errorReason: ErrorReasons.NetworkError,
        errorMessage:
          'No internet connection. Please check your network and try again.',
        token: null,
        valid: false,
      };
    }

    switch (error.status) {
      case 401:
        return {
          errorReason: ErrorReasons.Unauthorized,
          errorMessage: 'Invalid username or password',
          token: null,
          valid: false,
        };
      case 403:
        return {
          errorReason: ErrorReasons.AccessTokenExpired,
          errorMessage: 'Access token has expired',
          token: null,
          valid: false,
        };
      case 404:
        return {
          errorReason: ErrorReasons.InvalidEndpoint,
          errorMessage: 'The requested resource was not found',
          token: null,
          valid: false,
        };
      case 408:
      case 504:
        return {
          errorReason: ErrorReasons.RequestTimeout,
          errorMessage: 'The request timed out. Please try again',
          token: null,
          valid: false,
        };
      case 429:
        return {
          errorReason: ErrorReasons.TooManyLogins,
          errorMessage: 'Too many login attempts. Please try again later',
          token: null,
          valid: false,
        };
      case 500:
      case 502:
      case 503:
        return {
          errorReason: ErrorReasons.ServerError,
          errorMessage:
            'Server is currently unavailable. Please try again later',
          token: null,
          valid: false,
        };
      case 400: {
        let detailedMessage = error.error.message ?? 'Bad request';
        if (isDefined(error.error?.data?.fields)) {
          const fieldErrors = Object.values(error.error.data.fields)
            .map((field) => (field as { message: string }).message)
            .filter(Boolean)
            .join('. ');
          if (fieldErrors) {
            detailedMessage += `: ${fieldErrors}`;
          }
        }
        return {
          errorReason: ErrorReasons.BadRequest,
          errorMessage: detailedMessage,
          token: null,
          valid: false,
        };
      }
      default:
        return {
          errorReason: ErrorReasons.Unknown,
          errorMessage: 'An unexpected error occurred. Please try again',
          token: null,
          valid: false,
        };
    }
  }

  private showToastForError(errorObject: ApiErrorResponse): void {
    switch (errorObject.errorReason) {
      case ErrorReasons.Unauthorized:
        this.toastService.showError('Unauthorized', errorObject.errorMessage);
        break;
      case ErrorReasons.NetworkError:
        this.toastService.showError('Network Error', errorObject.errorMessage);
        break;
      case ErrorReasons.ServerError:
        this.toastService.showError('Server Error', errorObject.errorMessage);
        break;
      case ErrorReasons.InvalidEndpoint:
        this.toastService.showError(
          'Service Unavailable',
          errorObject.errorMessage,
        );
        break;
      case ErrorReasons.RequestTimeout:
        this.toastService.showError(
          'Request Timeout',
          errorObject.errorMessage,
        );
        break;
      case ErrorReasons.TooManyLogins:
        this.toastService.showError(
          'Too Many Logins',
          errorObject.errorMessage,
        );
        break;
      case ErrorReasons.BadRequest:
        this.toastService.showError(
          'Validation Error',
          errorObject.errorMessage,
        );
        break;
      case ErrorReasons.Unknown:
        this.toastService.showError('Error', errorObject.errorMessage);
        break;
    }
  }

  /**
   * Determines if an HTTP error should be retried based on the error type.
   * Only retries network errors, timeouts, and server errors.
   * Avoids retrying client errors like 401, 403, 400, etc.
   */
  private shouldRetryError(error: HttpErrorResponse): boolean {
    // Don't retry if offline
    if (!navigator.onLine) {
      return false;
    }

    // Only retry for specific error codes that might succeed on retry
    const retryableStatuses = [
      0, // Network error
      408, // Request Timeout
      429, // Too Many Requests (rate limiting)
      500, // Internal Server Error
      502, // Bad Gateway
      503, // Service Unavailable
      504, // Gateway Timeout
    ];

    return retryableStatuses.includes(error.status);
  }
}
